// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Blended AS metadata (RFC 8414)
	// (GET /.well-known/oauth-authorization-server)
	GetAuthorizationServerMetadata(ctx context.Context, request GetAuthorizationServerMetadataRequestObject) (GetAuthorizationServerMetadataResponseObject, error)
	// Protected-resource metadata — bare/default location (RFC 9728)
	// (GET /.well-known/oauth-protected-resource)
	GetProtectedResourceMetadata(ctx context.Context, request GetProtectedResourceMetadataRequestObject) (GetProtectedResourceMetadataResponseObject, error)
	// Protected-resource metadata for /agent-proxy (only when agent proxy enabled)
	// (GET /.well-known/oauth-protected-resource/agent-proxy)
	GetProtectedResourceMetadataAgentProxy(ctx context.Context, request GetProtectedResourceMetadataAgentProxyRequestObject) (GetProtectedResourceMetadataAgentProxyResponseObject, error)
	// Protected-resource metadata for /mcp (RFC 9728)
	// (GET /.well-known/oauth-protected-resource/mcp)
	GetProtectedResourceMetadataMcp(ctx context.Context, request GetProtectedResourceMetadataMcpRequestObject) (GetProtectedResourceMetadataMcpResponseObject, error)
	// List all accounts (admin only)
	// (GET /api/accounts)
	ListAccounts(ctx context.Context, request ListAccountsRequestObject) (ListAccountsResponseObject, error)
	// Export passkeys + endpoints as seed config (admin only)
	// (GET /api/accounts/export-seed)
	ExportSeedConfig(ctx context.Context, request ExportSeedConfigRequestObject) (ExportSeedConfigResponseObject, error)
	// Hard-delete an account + cascade (admin only)
	// (DELETE /api/accounts/{id})
	DeleteAccount(ctx context.Context, request DeleteAccountRequestObject) (DeleteAccountResponseObject, error)
	// Get a pending signing action
	// (GET /api/actions/{actionId})
	GetAction(ctx context.Context, request GetActionRequestObject) (GetActionResponseObject, error)
	// Deny a signing action
	// (POST /api/actions/{actionId}/deny)
	DenyAction(ctx context.Context, request DenyActionRequestObject) (DenyActionResponseObject, error)
	// Resolve a signing action (WebAuthn signature or key-approve)
	// (POST /api/actions/{actionId}/resolve)
	ResolveAction(ctx context.Context, request ResolveActionRequestObject) (ResolveActionResponseObject, error)
	// Query session-lifecycle events
	// (GET /api/audit/sessions)
	ListAuditSessions(ctx context.Context, request ListAuditSessionsRequestObject) (ListAuditSessionsResponseObject, error)
	// Query signing-request audit
	// (GET /api/audit/signings)
	ListAuditSignings(ctx context.Context, request ListAuditSigningsRequestObject) (ListAuditSigningsResponseObject, error)
	// Get one signing-request record
	// (GET /api/audit/signings/{id})
	GetAuditSigning(ctx context.Context, request GetAuditSigningRequestObject) (GetAuditSigningResponseObject, error)
	// Current account profile
	// (GET /api/auth/me)
	GetCurrentAccount(ctx context.Context, request GetCurrentAccountRequestObject) (GetCurrentAccountResponseObject, error)
	// Update current account (name, demo visibility)
	// (PUT /api/auth/me)
	UpdateCurrentAccount(ctx context.Context, request UpdateCurrentAccountRequestObject) (UpdateCurrentAccountResponseObject, error)
	// Whether any passkeys exist yet (first-run detection)
	// (GET /api/auth/passkey-status)
	GetPasskeyStatus(ctx context.Context, request GetPasskeyStatusRequestObject) (GetPasskeyStatusResponseObject, error)
	// Verify passkey + create the account (anonymous, rate-limited)
	// (POST /api/auth/register)
	FinishAccountRegistration(ctx context.Context, request FinishAccountRegistrationRequestObject) (FinishAccountRegistrationResponseObject, error)
	// Registration options for anonymous self-registration (rate-limited)
	// (POST /api/auth/register/options)
	StartAccountRegistration(ctx context.Context, request StartAccountRegistrationRequestObject) (StartAccountRegistrationResponseObject, error)
	// List authorized OAuth clients (one row per client_id)
	// (GET /api/auth/sessions)
	ListAuthorizedClients(ctx context.Context, request ListAuthorizedClientsRequestObject) (ListAuthorizedClientsResponseObject, error)
	// Sign out everywhere (step-up gated)
	// (POST /api/auth/sessions/revoke-all)
	RevokeAllAuthorizedClients(ctx context.Context, request RevokeAllAuthorizedClientsRequestObject) (RevokeAllAuthorizedClientsResponseObject, error)
	// Revoke one client's grant (step-up gated)
	// (DELETE /api/auth/sessions/{clientId})
	RevokeAuthorizedClient(ctx context.Context, request RevokeAuthorizedClientRequestObject) (RevokeAuthorizedClientResponseObject, error)
	// List account endpoints (+ demo endpoints if enabled)
	// (GET /api/endpoints)
	ListEndpoints(ctx context.Context, request ListEndpointsRequestObject) (ListEndpointsResponseObject, error)
	// Create endpoint (server generates the id)
	// (POST /api/endpoints)
	CreateEndpoint(ctx context.Context, request CreateEndpointRequestObject) (CreateEndpointResponseObject, error)
	// Delete endpoint
	// (DELETE /api/endpoints/{id})
	DeleteEndpoint(ctx context.Context, request DeleteEndpointRequestObject) (DeleteEndpointResponseObject, error)
	// Update endpoint (demo ids rejected)
	// (PUT /api/endpoints/{id})
	UpdateEndpoint(ctx context.Context, request UpdateEndpointRequestObject) (UpdateEndpointResponseObject, error)
	// No-passkey consent grant (valid only after a fresh login in-flow)
	// (POST /api/hydra/consent/approve)
	ApproveHydraConsent(ctx context.Context, request ApproveHydraConsentRequestObject) (ApproveHydraConsentResponseObject, error)
	// Passkey consent challenge
	// (POST /api/hydra/consent/options)
	StartHydraConsent(ctx context.Context, request StartHydraConsentRequestObject) (StartHydraConsentResponseObject, error)
	// Verify consent assertion, accept Hydra consent request
	// (POST /api/hydra/consent/verify)
	FinishHydraConsent(ctx context.Context, request FinishHydraConsentRequestObject) (FinishHydraConsentResponseObject, error)
	// Passkey login challenge (rate-limited)
	// (POST /api/hydra/login/options)
	StartHydraLogin(ctx context.Context, request StartHydraLoginRequestObject) (StartHydraLoginResponseObject, error)
	// Verify login assertion, accept Hydra login request
	// (POST /api/hydra/login/verify)
	FinishHydraLogin(ctx context.Context, request FinishHydraLoginRequestObject) (FinishHydraLoginResponseObject, error)
	// Mediated Dynamic Client Registration (RFC 7591)
	// (POST /api/hydra/register)
	RegisterOauthClient(ctx context.Context, request RegisterOauthClientRequestObject) (RegisterOauthClientResponseObject, error)
	// List file-based SSH keys (admin sees keys; non-admin sees empty)
	// (GET /api/keys)
	ListSshKeys(ctx context.Context, request ListSshKeysRequestObject) (ListSshKeysResponseObject, error)
	// Verify + enroll a passkey via invite (anonymous)
	// (POST /api/passkey-invite/register)
	FinishInvitePasskeyRegistration(ctx context.Context, request FinishInvitePasskeyRegistrationRequestObject) (FinishInvitePasskeyRegistrationResponseObject, error)
	// Registration options for invite enrollment (anonymous)
	// (POST /api/passkey-invite/register/options)
	StartInvitePasskeyRegistration(ctx context.Context, request StartInvitePasskeyRegistrationRequestObject) (StartInvitePasskeyRegistrationResponseObject, error)
	// Look up an invite by token (anonymous)
	// (GET /api/passkey-invite/{token})
	GetPasskeyInviteByToken(ctx context.Context, request GetPasskeyInviteByTokenRequestObject) (GetPasskeyInviteByTokenResponseObject, error)
	// Unregister a Web Push subscription
	// (DELETE /api/push/subscribe)
	DeletePushSubscription(ctx context.Context, request DeletePushSubscriptionRequestObject) (DeletePushSubscriptionResponseObject, error)
	// Register a Web Push subscription
	// (POST /api/push/subscribe)
	CreatePushSubscription(ctx context.Context, request CreatePushSubscriptionRequestObject) (CreatePushSubscriptionResponseObject, error)
	// List the account's terminal sessions
	// (GET /api/sessions)
	ListSessions(ctx context.Context, request ListSessionsRequestObject) (ListSessionsResponseObject, error)
	// Open an SSH session to an endpoint
	// (POST /api/sessions)
	CreateSession(ctx context.Context, request CreateSessionRequestObject) (CreateSessionResponseObject, error)
	// Close a session
	// (DELETE /api/sessions/{sessionId})
	CloseSession(ctx context.Context, request CloseSessionRequestObject) (CloseSessionResponseObject, error)
	// Read the tail of a session's output buffer
	// (GET /api/sessions/{sessionId}/tail)
	GetSessionTail(ctx context.Context, request GetSessionTailRequestObject) (GetSessionTailResponseObject, error)
	// Build info (curl-able without auth)
	// (GET /api/version)
	GetVersion(ctx context.Context, request GetVersionRequestObject) (GetVersionResponseObject, error)
	// List the account's passkeys
	// (GET /api/webauthn/credentials)
	ListPasskeys(ctx context.Context, request ListPasskeysRequestObject) (ListPasskeysResponseObject, error)
	// Confirm a pending invite passkey (step-up gated — confirm_passkey)
	// (POST /api/webauthn/credentials/{id}/confirm)
	ConfirmPasskey(ctx context.Context, request ConfirmPasskeyRequestObject) (ConfirmPasskeyResponseObject, error)
	// Rename a passkey (no step-up — cosmetic)
	// (PATCH /api/webauthn/credentials/{id}/label)
	UpdatePasskeyLabel(ctx context.Context, request UpdatePasskeyLabelRequestObject) (UpdatePasskeyLabelResponseObject, error)
	// Revoke a passkey (step-up gated — revoke_passkey)
	// (POST /api/webauthn/credentials/{id}/revoke)
	RevokePasskey(ctx context.Context, request RevokePasskeyRequestObject) (RevokePasskeyResponseObject, error)
	// Get the active passkey invite (if any)
	// (GET /api/webauthn/invite)
	GetPasskeyInvite(ctx context.Context, request GetPasskeyInviteRequestObject) (GetPasskeyInviteResponseObject, error)
	// Mint a passkey invite
	// (POST /api/webauthn/invite)
	CreatePasskeyInvite(ctx context.Context, request CreatePasskeyInviteRequestObject) (CreatePasskeyInviteResponseObject, error)
	// Verify + store a new passkey (step-up gated — register_passkey)
	// (POST /api/webauthn/register)
	FinishPasskeyRegistration(ctx context.Context, request FinishPasskeyRegistrationRequestObject) (FinishPasskeyRegistrationResponseObject, error)
	// Registration options for an in-account passkey add
	// (POST /api/webauthn/register/options)
	StartPasskeyRegistration(ctx context.Context, request StartPasskeyRegistrationRequestObject) (StartPasskeyRegistrationResponseObject, error)
	// Authentication options for a step-up ceremony
	// (POST /api/webauthn/stepup/options)
	StartStepUp(ctx context.Context, request StartStepUpRequestObject) (StartStepUpResponseObject, error)
	// Verify a step-up assertion, mint a single-use step-up token
	// (POST /api/webauthn/stepup/verify)
	FinishStepUp(ctx context.Context, request FinishStepUpRequestObject) (FinishStepUpResponseObject, error)
	// Browser bootstrap config (JS, not JSON)
	// (GET /config.js)
	GetConfigScript(ctx context.Context, request GetConfigScriptRequestObject) (GetConfigScriptResponseObject, error)
	// Liveness probe
	// (GET /health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

